const body = $input.first().json.body || $input.first().json;
const assessmentId = body.assessment_id;
const prospectEmail = body.prospect_email;
const firstName = body.first_name || 'there';
const company = body.company || 'your business';
const niche = body.niche || 'business';
if (!assessmentId || !prospectEmail) throw new Error('Missing assessment_id or prospect_email');
return [{ json: { assessmentId, prospectEmail, firstName, company, niche } }];

const count = $json.count || 0;
const alreadySent = count > 0;
return { json: { alreadySent } };

const parsed = $('Parse Input').first().json;
const assessmentId = parsed.assessmentId || parsed.assessment_id || '';
const prospectEmail = parsed.prospectEmail || parsed.prospect_email || '';
const firstName = parsed.firstName || parsed.first_name || 'there';
const company = parsed.company || parsed.business_name || '';
const niche = parsed.niche || 'business';

const subject = "Know someone who'd benefit from OpsJuice?";

const html = `<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px;color:#333">
<p>Hi ${firstName},</p>
<p>Thanks for trusting OpsJuice with your AI assessment. I hope it gave you a clear picture of where the fastest wins are.</p>
<p>Quick ask: do you know another business owner stuck in the same place you were? Repetitive work, time drain, never catching up. If you do, an intro would mean a lot.</p>
<p>If they complete an AI Assessment, I'll give you both <strong>$250 toward any OpsJuice build</strong>. Just reply with their name and email and I'll take it from there.</p>
<div style="margin:24px 0"><a href="https://cal.com/adrien-harrison/opsjuice-intro" style="background:#1a1a1a;color:#fff;padding:12px 24px;text-decoration:none;border-radius:4px;display:inline-block">Book a Free Strategy Call</a></div>
<p>Talk soon,<br>Adrien Harrison<br>Founder, OpsJuice | opsjuice.com</p>
</body></html>`;

const plain = `Hi ${firstName},

Thanks for trusting OpsJuice with your AI assessment. I hope it gave you a clear picture of where the fastest wins are.

Quick ask: do you know another business owner stuck in the same place you were? Repetitive work, time drain, never catching up. If you do, an intro would mean a lot.

If they complete an AI Assessment, I'll give you both $250 toward any OpsJuice build. Just reply with their name and email and I'll take it from there.

Book your free strategy call: https://cal.com/adrien-harrison/opsjuice-intro

Talk soon,
Adrien Harrison
Founder, OpsJuice | opsjuice.com`;

const supabaseRowJson = JSON.stringify({
  event_type: 'referral_ask_sent',
  actor: 'system',
  payload: {
    assessment_id: assessmentId,
    prospect_email: prospectEmail,
    first_name: firstName,
    company: company,
    niche: niche,
    triggered_at: new Date().toISOString(),
    incentive: '$250 toward any OpsJuice build when referred contact completes assessment'
  }
});

return [{ json: { assessmentId, prospectEmail, firstName, company, niche, subject, html, plain, supabaseRowJson } }];

